/**
 * SVG Component Library — hand-crafted parameterized SVG generators
 * for knobs, sliders, and buttons.
 *
 * Each generator returns a valid SVG string with proper interactive groups:
 * - Knobs: <g id="rotate"> wraps the indicator, centered at (cx, cy)
 * - Sliders: <g id="thumb"> wraps the movable handle
 * - Buttons: <g id="normal"> + <g id="pressed" display="none">
 *
 * All gradient/filter IDs are prefixed with a uid parameter to prevent collisions.
 */

// ═══════════════════════════════════════════════════════
// COLOR HELPERS
// ═══════════════════════════════════════════════════════

function hexToRgb(hex) {
  const h = hex.replace('#', '');
  const full = h.length === 3 ? h.split('').map(c => c + c).join('') : h;
  return {
    r: parseInt(full.substring(0, 2), 16) || 0,
    g: parseInt(full.substring(2, 4), 16) || 0,
    b: parseInt(full.substring(4, 6), 16) || 0,
  };
}

function rgbToHex(r, g, b) {
  return '#' + [r, g, b].map(v => Math.max(0, Math.min(255, Math.round(v))).toString(16).padStart(2, '0')).join('');
}

function lighten(hex, amount = 0.3) {
  const { r, g, b } = hexToRgb(hex);
  return rgbToHex(r + (255 - r) * amount, g + (255 - g) * amount, b + (255 - b) * amount);
}

function darken(hex, amount = 0.3) {
  const { r, g, b } = hexToRgb(hex);
  return rgbToHex(r * (1 - amount), g * (1 - amount), b * (1 - amount));
}

function hexToRgba(hex, alpha) {
  const { r, g, b } = hexToRgb(hex);
  return `rgba(${r},${g},${b},${alpha})`;
}

function escapeXml(str) {
  return (str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

// ═══════════════════════════════════════════════════════
// MOOG KNOB IMAGES — full (with highlights) + specular overlay
// Full images rotate; specular overlays stay fixed via CSS layers
// ═══════════════════════════════════════════════════════
// Pre-baked knob images (generated via Flux, no indicator/pointer)
const MOOG_ROUND_IMG = 'data:image/png;base64,';
const MOOG_ROUND_FLAT = 'data:image/png;base64,';
const MOOG_POINTER_IMG = 'data:image/png;base64,';
const MOOG_POINTER_FLAT = 'data:image/png;base64,';
const MOOG_OCTAVE_IMG = 'data:image/png;base64,';
const MOOG_OCTAVE_FLAT = 'data:image/png;base64,';

// Exported map — used as sprite for arc-indicator rendering
export const MOOG_KNOB_IMAGES = {
  'moog-round': { full: MOOG_ROUND_IMG, flat: MOOG_ROUND_FLAT },
  'moog-pointer': { full: MOOG_POINTER_IMG, flat: MOOG_POINTER_FLAT },
  'moog-octave': { full: MOOG_OCTAVE_IMG, flat: MOOG_OCTAVE_FLAT },
};

// ═══════════════════════════════════════════════════════
// KNOB GENERATORS (10 styles)
// ═══════════════════════════════════════════════════════

const knobGenerators = {
  'skirted-pointer': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 3;
    const ir = r * 0.72; // inner cap radius
    // Scale marks around the skirt (270 degree arc)
    const ticks = Array.from({ length: 11 }, (_, i) => {
      const frac = i / 10;
      const angle = (-225 + frac * 270) * Math.PI / 180;
      const x1 = cx + (r - 1) * Math.cos(angle), y1 = cy + (r - 1) * Math.sin(angle);
      const x2 = cx + (r - 5) * Math.cos(angle), y2 = cy + (r - 5) * Math.sin(angle);
      const isMajor = i % 5 === 0;
      return `<line x1="${x1.toFixed(1)}" y1="${y1.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${y2.toFixed(1)}" stroke="${hexToRgba('#ffffff', isMajor ? 0.5 : 0.25)}" stroke-width="${isMajor ? '1.2' : '0.6'}"/>`;
    }).join('\n  ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <!-- Skirt: dark ring with subtle top-left highlight -->
    <radialGradient id="${uid}-sk-skirt" cx="42%" cy="40%">
      <stop offset="0%" stop-color="${darken(body, 0.2)}"/>
      <stop offset="60%" stop-color="${darken(body, 0.45)}"/>
      <stop offset="85%" stop-color="${darken(body, 0.6)}"/>
      <stop offset="100%" stop-color="${darken(body, 0.75)}"/>
    </radialGradient>
    <!-- Inner cap: dome lit from top-left -->
    <radialGradient id="${uid}-sk-cap" cx="36%" cy="30%" fx="33%" fy="26%">
      <stop offset="0%" stop-color="${lighten(body, 0.4)}"/>
      <stop offset="20%" stop-color="${lighten(body, 0.2)}"/>
      <stop offset="50%" stop-color="${body}"/>
      <stop offset="80%" stop-color="${darken(body, 0.25)}"/>
      <stop offset="100%" stop-color="${darken(body, 0.5)}"/>
    </radialGradient>
    <!-- Bottom shadow for 3D depth -->
    <radialGradient id="${uid}-sk-bsh" cx="60%" cy="65%"><stop offset="0%" stop-color="${hexToRgba('#000000', 0.3)}"/><stop offset="100%" stop-color="${hexToRgba('#000000', 0)}"/></radialGradient>
    <!-- Specular highlight -->
    <radialGradient id="${uid}-sk-spec" cx="30%" cy="22%"><stop offset="0%" stop-color="${hexToRgba('#ffffff', 0.5)}"/><stop offset="50%" stop-color="${hexToRgba('#ffffff', 0.05)}"/><stop offset="100%" stop-color="${hexToRgba('#ffffff', 0)}"/></radialGradient>
    <filter id="${uid}-sk-sh"><feDropShadow dx="1" dy="2" stdDeviation="2.5" flood-color="#000" flood-opacity="0.65"/></filter>
    <filter id="${uid}-sk-blur"><feGaussianBlur stdDeviation="1.2"/></filter>
    <!-- Metallic diffuse light -->
    <filter id="${uid}-sk-met" color-interpolation-filters="sRGB">
      <feDiffuseLighting in="SourceGraphic" result="light" lighting-color="${lighten(body, 0.5)}" surfaceScale="2.5">
        <feDistantLight azimuth="220" elevation="50"/>
      </feDiffuseLighting>
      <feComposite in="SourceGraphic" in2="light" operator="arithmetic" k1="0.6" k2="0.4" k3="0" k4="0"/>
      <feComposite in2="SourceAlpha" operator="in"/>
    </filter>
  </defs>
  <!-- Outer skirt ring -->
  <circle cx="${cx}" cy="${cy}" r="${r}" fill="url(#${uid}-sk-skirt)" stroke="${darken(body, 0.7)}" stroke-width="1"/>
  <!-- Skirt bevel highlight -->
  <circle cx="${cx}" cy="${cy}" r="${r - 1}" fill="none" stroke="${hexToRgba('#ffffff', 0.06)}" stroke-width="1"/>
  ${ticks}
  <!-- Inner raised cap with shadow -->
  <circle cx="${cx}" cy="${cy}" r="${ir}" fill="url(#${uid}-sk-cap)" stroke="${darken(body, 0.4)}" stroke-width="1.2" filter="url(#${uid}-sk-sh)"/>
  <!-- Metallic sheen on cap -->
  <circle cx="${cx}" cy="${cy}" r="${ir - 1}" fill="url(#${uid}-sk-cap)" filter="url(#${uid}-sk-met)" opacity="0.35"/>
  <!-- Bottom shadow overlay -->
  <circle cx="${cx}" cy="${cy}" r="${ir - 1}" fill="url(#${uid}-sk-bsh)"/>
  <!-- Specular highlight (blurred) -->
  <circle cx="${cx * 0.8}" cy="${cy * 0.72}" r="${ir * 0.4}" fill="url(#${uid}-sk-spec)" filter="url(#${uid}-sk-blur)"/>
  <!-- Rim highlight -->
  <circle cx="${cx}" cy="${cy}" r="${ir}" fill="none" stroke="${hexToRgba('#ffffff', 0.08)}" stroke-width="0.8"/>
  <!-- Center screw -->
  <circle cx="${cx}" cy="${cy}" r="${ir * 0.13}" fill="${darken(body, 0.3)}" stroke="${darken(body, 0.5)}" stroke-width="0.7"/>
  <line x1="${cx - ir * 0.07}" y1="${cy}" x2="${cx + ir * 0.07}" y2="${cy}" stroke="${hexToRgba('#ffffff', 0.12)}" stroke-width="0.6"/>
  <!-- Rotating pointer -->
  <g id="rotate">
    <polygon points="${cx},${cy - ir + 2} ${cx - ir * 0.15},${cy - ir * 0.45} ${cx + ir * 0.15},${cy - ir * 0.45}" fill="${indicator}" stroke="${darken(indicator, 0.25)}" stroke-width="0.8" stroke-linejoin="round"/>
    <polygon points="${cx - 1},${cy - ir + 3} ${cx - ir * 0.08},${cy - ir * 0.5} ${cx + ir * 0.04},${cy - ir * 0.5}" fill="${lighten(indicator, 0.3)}" opacity="0.35"/>
  </g>
</svg>`;
  },

  'chicken-head': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 3;
    const kr = r * 0.85; // knob cap radius
    // Scale marks (270 degree arc)
    const ticks = Array.from({ length: 11 }, (_, i) => {
      const frac = i / 10;
      const angle = (-225 + frac * 270) * Math.PI / 180;
      const x1 = cx + (r + 1) * Math.cos(angle), y1 = cy + (r + 1) * Math.sin(angle);
      const x2 = cx + (r - 3) * Math.cos(angle), y2 = cy + (r - 3) * Math.sin(angle);
      const isMajor = i % 5 === 0;
      return `<line x1="${x1.toFixed(1)}" y1="${y1.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${y2.toFixed(1)}" stroke="${hexToRgba('#ffffff', isMajor ? 0.5 : 0.2)}" stroke-width="${isMajor ? '1.2' : '0.6'}"/>`;
    }).join('\n  ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <!-- Base ring gradient -->
    <radialGradient id="${uid}-ch-base" cx="50%" cy="50%"><stop offset="0%" stop-color="${darken(body, 0.25)}"/><stop offset="70%" stop-color="${darken(body, 0.5)}"/><stop offset="100%" stop-color="${darken(body, 0.7)}"/></radialGradient>
    <!-- Main body: off-center focal point simulates dome curvature lit from top-left -->
    <radialGradient id="${uid}-ch-body" cx="38%" cy="32%" fx="35%" fy="28%">
      <stop offset="0%" stop-color="${lighten(body, 0.35)}"/>
      <stop offset="25%" stop-color="${lighten(body, 0.15)}"/>
      <stop offset="55%" stop-color="${body}"/>
      <stop offset="80%" stop-color="${darken(body, 0.25)}"/>
      <stop offset="100%" stop-color="${darken(body, 0.45)}"/>
    </radialGradient>
    <!-- Bottom shadow: darkens lower-right for 3D depth -->
    <radialGradient id="${uid}-ch-bshadow" cx="65%" cy="70%"><stop offset="0%" stop-color="${hexToRgba('#000000', 0.25)}"/><stop offset="100%" stop-color="${hexToRgba('#000000', 0)}"/></radialGradient>
    <!-- Top-left specular highlight -->
    <radialGradient id="${uid}-ch-spec" cx="32%" cy="25%" fx="30%" fy="22%"><stop offset="0%" stop-color="${hexToRgba('#ffffff', 0.45)}"/><stop offset="40%" stop-color="${hexToRgba('#ffffff', 0.08)}"/><stop offset="100%" stop-color="${hexToRgba('#ffffff', 0)}"/></radialGradient>
    <!-- Rim light (top edge catch light) -->
    <linearGradient id="${uid}-ch-rim" x1="0.3" y1="0" x2="0.7" y2="1"><stop offset="0%" stop-color="${hexToRgba('#ffffff', 0.12)}"/><stop offset="50%" stop-color="${hexToRgba('#ffffff', 0)}"/><stop offset="100%" stop-color="${hexToRgba('#ffffff', 0.03)}"/></linearGradient>
    <!-- Drop shadow filter -->
    <filter id="${uid}-ch-sh"><feDropShadow dx="1" dy="2" stdDeviation="3" flood-color="#000" flood-opacity="0.7"/></filter>
    <!-- Highlight blur filter -->
    <filter id="${uid}-ch-blur"><feGaussianBlur stdDeviation="1.5"/></filter>
    <!-- Diffuse lighting for metallic sheen -->
    <filter id="${uid}-ch-metal" color-interpolation-filters="sRGB">
      <feDiffuseLighting in="SourceGraphic" result="light" lighting-color="${lighten(body, 0.6)}" surfaceScale="3">
        <feDistantLight azimuth="225" elevation="55"/>
      </feDiffuseLighting>
      <feComposite in="SourceGraphic" in2="light" operator="arithmetic" k1="0.7" k2="0.3" k3="0" k4="0"/>
      <feComposite in2="SourceAlpha" operator="in"/>
    </filter>
  </defs>
  <!-- Outer base ring -->
  <circle cx="${cx}" cy="${cy}" r="${r}" fill="url(#${uid}-ch-base)" stroke="${darken(body, 0.6)}" stroke-width="0.8"/>
  ${ticks}
  <!-- Main knob body with drop shadow -->
  <circle cx="${cx}" cy="${cy}" r="${kr}" fill="url(#${uid}-ch-body)" stroke="${darken(body, 0.4)}" stroke-width="1.2" filter="url(#${uid}-ch-sh)"/>
  <!-- Metallic sheen overlay -->
  <circle cx="${cx}" cy="${cy}" r="${kr - 1}" fill="url(#${uid}-ch-body)" filter="url(#${uid}-ch-metal)" opacity="0.4"/>
  <!-- Bottom shadow overlay for 3D depth -->
  <circle cx="${cx}" cy="${cy}" r="${kr - 1}" fill="url(#${uid}-ch-bshadow)"/>
  <!-- Rim light -->
  <circle cx="${cx}" cy="${cy}" r="${kr - 1}" fill="none" stroke="url(#${uid}-ch-rim)" stroke-width="1.5"/>
  <!-- Specular highlight (blurred for realism) -->
  <circle cx="${cx * 0.82}" cy="${cy * 0.78}" r="${kr * 0.35}" fill="url(#${uid}-ch-spec)" filter="url(#${uid}-ch-blur)"/>
  <!-- Accent ring on knob edge -->
  <circle cx="${cx}" cy="${cy}" r="${kr}" fill="none" stroke="${hexToRgba(accent, 0.35)}" stroke-width="1.5"/>
  <!-- Center mounting screw -->
  <circle cx="${cx}" cy="${cy}" r="${r * 0.10}" fill="${darken(body, 0.3)}" stroke="${darken(body, 0.5)}" stroke-width="0.8"/>
  <line x1="${cx - r * 0.06}" y1="${cy - r * 0.06}" x2="${cx + r * 0.06}" y2="${cy + r * 0.06}" stroke="${hexToRgba('#ffffff', 0.15)}" stroke-width="0.7"/>
  <!-- Rotating pointer group -->
  <g id="rotate">
    <polygon points="${cx},${cy - kr + 2} ${cx - kr * 0.14},${cy - kr * 0.35} ${cx + kr * 0.14},${cy - kr * 0.35}" fill="${indicator}" stroke="${darken(indicator, 0.25)}" stroke-width="0.8" stroke-linejoin="round"/>
    <polygon points="${cx},${cy - kr + 3} ${cx - kr * 0.08},${cy - kr * 0.4} ${cx + kr * 0.04},${cy - kr * 0.4}" fill="${lighten(indicator, 0.25)}" opacity="0.4"/>
  </g>
</svg>`;
  },

  'dome-line': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 3;
    const dr = r * 0.82; // dome radius
    // Scale marks
    const ticks = Array.from({ length: 21 }, (_, i) => {
      const frac = i / 20;
      const angle = (-225 + frac * 270) * Math.PI / 180;
      const isMajor = i % 5 === 0;
      const len = isMajor ? 5 : 2.5;
      const x1 = cx + r * Math.cos(angle), y1 = cy + r * Math.sin(angle);
      const x2 = cx + (r - len) * Math.cos(angle), y2 = cy + (r - len) * Math.sin(angle);
      return `<line x1="${x1.toFixed(1)}" y1="${y1.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${y2.toFixed(1)}" stroke="${hexToRgba('#ffffff', isMajor ? 0.45 : 0.18)}" stroke-width="${isMajor ? '1' : '0.5'}"/>`;
    }).join('\n  ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <radialGradient id="${uid}-dm-outer" cx="45%" cy="42%">
      <stop offset="0%" stop-color="${darken(body, 0.15)}"/>
      <stop offset="60%" stop-color="${darken(body, 0.35)}"/>
      <stop offset="100%" stop-color="${darken(body, 0.6)}"/>
    </radialGradient>
    <!-- Dome: bright metallic top-left, dark bottom-right -->
    <radialGradient id="${uid}-dm-dome" cx="35%" cy="28%" fx="32%" fy="24%">
      <stop offset="0%" stop-color="${lighten(body, 0.55)}"/>
      <stop offset="20%" stop-color="${lighten(body, 0.3)}"/>
      <stop offset="50%" stop-color="${body}"/>
      <stop offset="78%" stop-color="${darken(body, 0.3)}"/>
      <stop offset="100%" stop-color="${darken(body, 0.5)}"/>
    </radialGradient>
    <!-- Bottom shadow -->
    <radialGradient id="${uid}-dm-bsh" cx="62%" cy="68%"><stop offset="0%" stop-color="${hexToRgba('#000000', 0.3)}"/><stop offset="100%" stop-color="${hexToRgba('#000000', 0)}"/></radialGradient>
    <!-- Specular highlight -->
    <radialGradient id="${uid}-dm-spec" cx="28%" cy="22%"><stop offset="0%" stop-color="${hexToRgba('#ffffff', 0.55)}"/><stop offset="35%" stop-color="${hexToRgba('#ffffff', 0.1)}"/><stop offset="100%" stop-color="${hexToRgba('#ffffff', 0)}"/></radialGradient>
    <filter id="${uid}-dm-sh"><feDropShadow dx="1" dy="2" stdDeviation="2.5" flood-color="#000" flood-opacity="0.6"/></filter>
    <filter id="${uid}-dm-blur"><feGaussianBlur stdDeviation="1.5"/></filter>
    <filter id="${uid}-dm-met" color-interpolation-filters="sRGB">
      <feSpecularLighting in="SourceGraphic" result="spec" lighting-color="#ffffff" surfaceScale="2" specularConstant="0.8" specularExponent="25">
        <fePointLight x="${cx * 0.6}" y="${cy * 0.4}" z="40"/>
      </feSpecularLighting>
      <feComposite in="spec" in2="SourceAlpha" operator="in" result="specMask"/>
      <feComposite in="SourceGraphic" in2="specMask" operator="arithmetic" k1="0" k2="1" k3="0.3" k4="0"/>
    </filter>
  </defs>
  <!-- Outer ring -->
  <circle cx="${cx}" cy="${cy}" r="${r}" fill="url(#${uid}-dm-outer)" stroke="${darken(body, 0.55)}" stroke-width="0.8"/>
  ${ticks}
  <!-- Dome body with shadow -->
  <circle cx="${cx}" cy="${cy}" r="${dr}" fill="url(#${uid}-dm-dome)" stroke="${darken(body, 0.45)}" stroke-width="1" filter="url(#${uid}-dm-sh)"/>
  <!-- Metallic specular lighting -->
  <circle cx="${cx}" cy="${cy}" r="${dr - 1}" fill="url(#${uid}-dm-dome)" filter="url(#${uid}-dm-met)" opacity="0.5"/>
  <!-- Bottom shadow -->
  <circle cx="${cx}" cy="${cy}" r="${dr - 1}" fill="url(#${uid}-dm-bsh)"/>
  <!-- Specular highlight blob -->
  <circle cx="${cx * 0.78}" cy="${cy * 0.7}" r="${dr * 0.35}" fill="url(#${uid}-dm-spec)" filter="url(#${uid}-dm-blur)"/>
  <!-- Rim highlight -->
  <circle cx="${cx}" cy="${cy}" r="${dr}" fill="none" stroke="${hexToRgba('#ffffff', 0.07)}" stroke-width="1"/>
  <!-- Center accent cap -->
  <circle cx="${cx}" cy="${cy}" r="${r * 0.18}" fill="${accent}" stroke="${darken(accent, 0.35)}" stroke-width="1"/>
  <circle cx="${cx * 0.94}" cy="${cy * 0.9}" r="${r * 0.05}" fill="${hexToRgba('#ffffff', 0.3)}"/>
  <!-- Rotating indicator line -->
  <g id="rotate"><line x1="${cx}" y1="${cy}" x2="${cx}" y2="${cy - dr + 2}" stroke="${indicator}" stroke-width="2.5" stroke-linecap="round"/><line x1="${cx + 0.5}" y1="${cy}" x2="${cx + 0.5}" y2="${cy - dr + 4}" stroke="${lighten(indicator, 0.3)}" stroke-width="0.8" stroke-linecap="round" opacity="0.4"/></g>
</svg>`;
  },

  'soft-rubber': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 2;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <radialGradient id="${uid}-sr-bg" cx="50%" cy="50%"><stop offset="0%" stop-color="${lighten(body, 0.08)}"/><stop offset="100%" stop-color="${darken(body, 0.15)}"/></radialGradient>
  </defs>
  <circle cx="${cx}" cy="${cy}" r="${r}" fill="url(#${uid}-sr-bg)" stroke="${hexToRgba(accent, 0.3)}" stroke-width="1"/>
  <line x1="${cx - r * 0.4}" y1="${cy - r * 0.4}" x2="${cx + r * 0.4}" y2="${cy + r * 0.4}" stroke="${hexToRgba('#ffffff', 0.04)}" stroke-width="0.5"/>
  <line x1="${cx + r * 0.4}" y1="${cy - r * 0.4}" x2="${cx - r * 0.4}" y2="${cy + r * 0.4}" stroke="${hexToRgba('#ffffff', 0.04)}" stroke-width="0.5"/>
  <line x1="${cx}" y1="${cy - r * 0.55}" x2="${cx}" y2="${cy + r * 0.55}" stroke="${hexToRgba('#ffffff', 0.03)}" stroke-width="0.5"/>
  <line x1="${cx - r * 0.55}" y1="${cy}" x2="${cx + r * 0.55}" y2="${cy}" stroke="${hexToRgba('#ffffff', 0.03)}" stroke-width="0.5"/>
  <g id="rotate"><circle cx="${cx}" cy="${cy - r + 5}" r="${r * 0.08}" fill="${indicator}"/></g>
</svg>`;
  },

  'chrome-cap': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 2;
    const capR = r * 0.4;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <radialGradient id="${uid}-cc-ring" cx="42%" cy="40%">
      <stop offset="0%" stop-color="${lighten(body, 0.1)}"/>
      <stop offset="55%" stop-color="${body}"/>
      <stop offset="85%" stop-color="${darken(body, 0.3)}"/>
      <stop offset="100%" stop-color="${darken(body, 0.5)}"/>
    </radialGradient>
    <!-- Chrome cap: mirror-like with strong specular -->
    <radialGradient id="${uid}-cc-cap" cx="32%" cy="25%" fx="28%" fy="20%">
      <stop offset="0%" stop-color="#ffffff"/>
      <stop offset="15%" stop-color="${lighten(accent, 0.6)}"/>
      <stop offset="45%" stop-color="${lighten(accent, 0.2)}"/>
      <stop offset="75%" stop-color="${darken(accent, 0.15)}"/>
      <stop offset="100%" stop-color="${darken(accent, 0.4)}"/>
    </radialGradient>
    <radialGradient id="${uid}-cc-bsh" cx="60%" cy="65%"><stop offset="0%" stop-color="${hexToRgba('#000000', 0.25)}"/><stop offset="100%" stop-color="${hexToRgba('#000000', 0)}"/></radialGradient>
    <filter id="${uid}-cc-sh"><feDropShadow dx="1" dy="2" stdDeviation="2" flood-color="#000" flood-opacity="0.55"/></filter>
    <filter id="${uid}-cc-blur"><feGaussianBlur stdDeviation="0.8"/></filter>
    <filter id="${uid}-cc-chrome" color-interpolation-filters="sRGB">
      <feSpecularLighting in="SourceGraphic" result="spec" lighting-color="#ffffff" surfaceScale="3" specularConstant="1.2" specularExponent="40">
        <fePointLight x="${cx * 0.5}" y="${cy * 0.3}" z="50"/>
      </feSpecularLighting>
      <feComposite in="spec" in2="SourceAlpha" operator="in" result="specMask"/>
      <feComposite in="SourceGraphic" in2="specMask" operator="arithmetic" k1="0" k2="1" k3="0.4" k4="0"/>
    </filter>
  </defs>
  <!-- Body ring -->
  <circle cx="${cx}" cy="${cy}" r="${r}" fill="url(#${uid}-cc-ring)" stroke="${darken(body, 0.55)}" stroke-width="1" filter="url(#${uid}-cc-sh)"/>
  <circle cx="${cx}" cy="${cy}" r="${r - 1}" fill="url(#${uid}-cc-bsh)"/>
  <circle cx="${cx}" cy="${cy}" r="${r * 0.92}" fill="none" stroke="${hexToRgba('#ffffff', 0.06)}" stroke-width="0.8"/>
  <!-- Chrome cap -->
  <circle cx="${cx}" cy="${cy}" r="${capR}" fill="url(#${uid}-cc-cap)" stroke="${darken(accent, 0.35)}" stroke-width="1"/>
  <circle cx="${cx}" cy="${cy}" r="${capR - 1}" fill="url(#${uid}-cc-cap)" filter="url(#${uid}-cc-chrome)" opacity="0.5"/>
  <!-- Cap highlight -->
  <circle cx="${cx * 0.88}" cy="${cy * 0.82}" r="${capR * 0.3}" fill="${hexToRgba('#ffffff', 0.4)}" filter="url(#${uid}-cc-blur)"/>
  <g id="rotate"><line x1="${cx}" y1="${cy}" x2="${cx}" y2="${cy - r + 3}" stroke="${indicator}" stroke-width="2.5" stroke-linecap="round"/><line x1="${cx + 0.5}" y1="${cy}" x2="${cx + 0.5}" y2="${cy - r + 5}" stroke="${lighten(indicator, 0.3)}" stroke-width="0.7" opacity="0.4" stroke-linecap="round"/></g>
</svg>`;
  },

  'glass-ring': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 3;
    // LED segments around the ring
    const segs = Array.from({ length: 16 }, (_, i) => {
      const frac = i / 15;
      const angle = (-225 + frac * 270) * Math.PI / 180;
      const x = cx + (r - 3) * Math.cos(angle), y = cy + (r - 3) * Math.sin(angle);
      const lit = i < 11;
      return `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="1.8" fill="${indicator}" opacity="${lit ? '0.9' : '0.08'}"/>`;
    }).join('\n  ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <!-- Glass body: dark with subtle color tint -->
    <radialGradient id="${uid}-gr-body" cx="40%" cy="35%" fx="36%" fy="30%">
      <stop offset="0%" stop-color="${hexToRgba(indicator, 0.12)}"/>
      <stop offset="30%" stop-color="${darken(body, 0.1)}"/>
      <stop offset="70%" stop-color="${darken(body, 0.3)}"/>
      <stop offset="100%" stop-color="${darken(body, 0.55)}"/>
    </radialGradient>
    <!-- Glass refraction highlight -->
    <radialGradient id="${uid}-gr-glass" cx="30%" cy="25%"><stop offset="0%" stop-color="${hexToRgba('#ffffff', 0.2)}"/><stop offset="60%" stop-color="${hexToRgba('#ffffff', 0.02)}"/><stop offset="100%" stop-color="${hexToRgba('#ffffff', 0)}"/></radialGradient>
    <!-- Inner glow from indicator color -->
    <radialGradient id="${uid}-gr-inner" cx="50%" cy="50%"><stop offset="0%" stop-color="${hexToRgba(indicator, 0.15)}"/><stop offset="50%" stop-color="${hexToRgba(indicator, 0.03)}"/><stop offset="100%" stop-color="${hexToRgba(indicator, 0)}"/></radialGradient>
    <filter id="${uid}-gr-glow"><feGaussianBlur stdDeviation="3" result="blur"/><feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
    <filter id="${uid}-gr-ledglow"><feGaussianBlur stdDeviation="1.5" result="blur"/><feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
    <filter id="${uid}-gr-sh"><feDropShadow dx="0" dy="1" stdDeviation="3" flood-color="${indicator}" flood-opacity="0.2"/></filter>
    <filter id="${uid}-gr-blur"><feGaussianBlur stdDeviation="1"/></filter>
  </defs>
  <!-- Outer glow ring -->
  <circle cx="${cx}" cy="${cy}" r="${r + 1}" fill="none" stroke="${hexToRgba(indicator, 0.1)}" stroke-width="2" filter="url(#${uid}-gr-glow)"/>
  <!-- Glass body -->
  <circle cx="${cx}" cy="${cy}" r="${r}" fill="url(#${uid}-gr-body)" stroke="${hexToRgba(indicator, 0.25)}" stroke-width="1" filter="url(#${uid}-gr-sh)"/>
  <!-- Glowing LED ring -->
  <circle cx="${cx}" cy="${cy}" r="${r - 1}" fill="none" stroke="${hexToRgba(indicator, 0.2)}" stroke-width="4" filter="url(#${uid}-gr-ledglow)"/>
  ${segs}
  <!-- Glass refraction highlight -->
  <circle cx="${cx * 0.8}" cy="${cy * 0.75}" r="${r * 0.4}" fill="url(#${uid}-gr-glass)" filter="url(#${uid}-gr-blur)"/>
  <!-- Inner ambient glow -->
  <circle cx="${cx}" cy="${cy}" r="${r * 0.55}" fill="url(#${uid}-gr-inner)"/>
  <!-- Center LED dot -->
  <circle cx="${cx}" cy="${cy}" r="${r * 0.12}" fill="${indicator}" opacity="0.6" filter="url(#${uid}-gr-ledglow)"/>
  <!-- Rotating indicator -->
  <g id="rotate"><line x1="${cx}" y1="${cy}" x2="${cx}" y2="${cy - r + 5}" stroke="${indicator}" stroke-width="2.5" stroke-linecap="round" filter="url(#${uid}-gr-glow)"/><circle cx="${cx}" cy="${cy - r + 5}" r="${r * 0.06}" fill="${indicator}"/></g>
</svg>`;
  },

  'hex-bolt': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 2;
    const pts = Array.from({ length: 6 }, (_, i) => {
      const a = (Math.PI / 3) * i - Math.PI / 6;
      return `${cx + r * Math.cos(a)},${cy + r * Math.sin(a)}`;
    }).join(' ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <linearGradient id="${uid}-hx-bg" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="${lighten(body, 0.2)}"/><stop offset="100%" stop-color="${darken(body, 0.25)}"/></linearGradient>
  </defs>
  <polygon points="${pts}" fill="url(#${uid}-hx-bg)" stroke="${accent}" stroke-width="1.5" stroke-linejoin="round"/>
  <circle cx="${cx}" cy="${cy}" r="${r * 0.35}" fill="${darken(body, 0.15)}" stroke="${hexToRgba(accent, 0.3)}" stroke-width="0.5"/>
  <g id="rotate"><line x1="${cx}" y1="${cy}" x2="${cx}" y2="${cy - r * 0.75}" stroke="${indicator}" stroke-width="2" stroke-linecap="round"/></g>
</svg>`;
  },

  'minimal-dot': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 3;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="${hexToRgba(accent, 0.35)}" stroke-width="1.5"/>
  <g id="rotate"><circle cx="${cx}" cy="${cy - r + 1}" r="${r * 0.1}" fill="${indicator}"/></g>
</svg>`;
  },

  'led-ring': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 2;
    const ledR = r * 0.06;
    const ringR = r * 0.85;
    const leds = Array.from({ length: 12 }, (_, i) => {
      const frac = i / 11;
      const angle = (-225 + frac * 270) * Math.PI / 180;
      const x = cx + ringR * Math.cos(angle);
      const y = cy + ringR * Math.sin(angle);
      const lit = i < 8;
      return `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="${ledR}" fill="${indicator}" opacity="${lit ? '0.9' : '0.15'}"/>`;
    }).join('\n  ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <circle cx="${cx}" cy="${cy}" r="${r * 0.55}" fill="${darken(body, 0.2)}" stroke="${hexToRgba(accent, 0.2)}" stroke-width="0.5"/>
  ${leds}
  <g id="rotate"><line x1="${cx}" y1="${cy}" x2="${cx}" y2="${cy - r * 0.45}" stroke="${indicator}" stroke-width="1.5" stroke-linecap="round"/></g>
</svg>`;
  },

  'bakelite': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 3;
    const kr = r * 0.88;
    const ticks = Array.from({ length: 11 }, (_, i) => {
      const frac = i / 10;
      const angle = (-225 + frac * 270) * Math.PI / 180;
      const x1 = cx + (r + 1) * Math.cos(angle), y1 = cy + (r + 1) * Math.sin(angle);
      const x2 = cx + (r - 3) * Math.cos(angle), y2 = cy + (r - 3) * Math.sin(angle);
      const isMajor = i % 5 === 0;
      return `<line x1="${x1.toFixed(1)}" y1="${y1.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${y2.toFixed(1)}" stroke="${hexToRgba('#ffffff', isMajor ? 0.45 : 0.2)}" stroke-width="${isMajor ? '1' : '0.6'}"/>`;
    }).join('\n  ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <!-- Bakelite body: warm plastic with slight gloss -->
    <radialGradient id="${uid}-bk-body" cx="38%" cy="32%" fx="35%" fy="28%">
      <stop offset="0%" stop-color="${lighten(body, 0.3)}"/>
      <stop offset="25%" stop-color="${lighten(body, 0.12)}"/>
      <stop offset="55%" stop-color="${body}"/>
      <stop offset="82%" stop-color="${darken(body, 0.22)}"/>
      <stop offset="100%" stop-color="${darken(body, 0.4)}"/>
    </radialGradient>
    <radialGradient id="${uid}-bk-bsh" cx="62%" cy="68%"><stop offset="0%" stop-color="${hexToRgba('#000000', 0.25)}"/><stop offset="100%" stop-color="${hexToRgba('#000000', 0)}"/></radialGradient>
    <radialGradient id="${uid}-bk-spec" cx="30%" cy="24%"><stop offset="0%" stop-color="${hexToRgba('#ffffff', 0.4)}"/><stop offset="40%" stop-color="${hexToRgba('#ffffff', 0.06)}"/><stop offset="100%" stop-color="${hexToRgba('#ffffff', 0)}"/></radialGradient>
    <filter id="${uid}-bk-sh"><feDropShadow dx="1" dy="2" stdDeviation="2.5" flood-color="#000" flood-opacity="0.6"/></filter>
    <filter id="${uid}-bk-blur"><feGaussianBlur stdDeviation="1.2"/></filter>
    <filter id="${uid}-bk-met" color-interpolation-filters="sRGB">
      <feDiffuseLighting in="SourceGraphic" result="light" lighting-color="${lighten(body, 0.4)}" surfaceScale="2">
        <feDistantLight azimuth="230" elevation="50"/>
      </feDiffuseLighting>
      <feComposite in="SourceGraphic" in2="light" operator="arithmetic" k1="0.5" k2="0.5" k3="0" k4="0"/>
      <feComposite in2="SourceAlpha" operator="in"/>
    </filter>
  </defs>
  <!-- Dark base plate -->
  <circle cx="${cx}" cy="${cy}" r="${r}" fill="${darken(body, 0.55)}" stroke="${darken(body, 0.7)}" stroke-width="0.8"/>
  ${ticks}
  <!-- Bakelite body with shadow -->
  <circle cx="${cx}" cy="${cy}" r="${kr}" fill="url(#${uid}-bk-body)" stroke="${accent}" stroke-width="2" filter="url(#${uid}-bk-sh)"/>
  <!-- Diffuse lighting overlay -->
  <circle cx="${cx}" cy="${cy}" r="${kr - 1}" fill="url(#${uid}-bk-body)" filter="url(#${uid}-bk-met)" opacity="0.35"/>
  <!-- Bottom shadow -->
  <circle cx="${cx}" cy="${cy}" r="${kr - 1}" fill="url(#${uid}-bk-bsh)"/>
  <!-- Specular highlight -->
  <circle cx="${cx * 0.82}" cy="${cy * 0.75}" r="${kr * 0.35}" fill="url(#${uid}-bk-spec)" filter="url(#${uid}-bk-blur)"/>
  <!-- Concentric rings (bakelite texture) -->
  <circle cx="${cx}" cy="${cy}" r="${kr * 0.78}" fill="none" stroke="${hexToRgba('#ffffff', 0.04)}" stroke-width="0.5"/>
  <circle cx="${cx}" cy="${cy}" r="${kr * 0.6}" fill="none" stroke="${hexToRgba('#ffffff', 0.03)}" stroke-width="0.5"/>
  <!-- Center brass hub -->
  <circle cx="${cx}" cy="${cy}" r="${r * 0.13}" fill="${darken(body, 0.2)}" stroke="${darken(body, 0.4)}" stroke-width="0.8"/>
  <circle cx="${cx * 0.97}" cy="${cy * 0.95}" r="${r * 0.03}" fill="${hexToRgba('#ffffff', 0.15)}"/>
  <!-- Rotating indicator tab -->
  <g id="rotate"><rect x="${cx - r * 0.07}" y="${cy - kr + 2}" width="${r * 0.14}" height="${kr * 0.48}" rx="${r * 0.035}" fill="${indicator}" stroke="${darken(indicator, 0.2)}" stroke-width="0.7"/>
  <rect x="${cx - r * 0.04}" y="${cy - kr + 3}" width="${r * 0.06}" height="${kr * 0.25}" rx="${r * 0.02}" fill="${lighten(indicator, 0.25)}" opacity="0.35"/></g>
</svg>`;
  },

  'pointer-cap': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 2;
    const capR = r * 0.3;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <radialGradient id="${uid}-pc-bg" cx="50%" cy="50%"><stop offset="0%" stop-color="${lighten(body, 0.1)}"/><stop offset="100%" stop-color="${darken(body, 0.25)}"/></radialGradient>
  </defs>
  <circle cx="${cx}" cy="${cy}" r="${r}" fill="url(#${uid}-pc-bg)" stroke="${darken(body, 0.4)}" stroke-width="1.5"/>
  <circle cx="${cx}" cy="${cy}" r="${r * 0.88}" fill="none" stroke="${hexToRgba('#ffffff', 0.06)}" stroke-width="0.5"/>
  <circle cx="${cx}" cy="${cy}" r="${capR}" fill="${lighten(body, 0.2)}" stroke="${darken(body, 0.3)}" stroke-width="1"/>
  <circle cx="${cx}" cy="${cy}" r="${capR * 0.4}" fill="${darken(body, 0.1)}"/>
  <g id="rotate"><line x1="${cx}" y1="${cy - capR * 0.5}" x2="${cx}" y2="${cy - r + 1}" stroke="${indicator}" stroke-width="2.5" stroke-linecap="round"/></g>
</svg>`;
  },

  'collet-knob': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 2;
    // Knurled grip lines
    const knurls = Array.from({ length: 24 }, (_, i) => {
      const a = (Math.PI * 2 / 24) * i;
      const x1 = cx + r * 0.75 * Math.cos(a), y1 = cy + r * 0.75 * Math.sin(a);
      const x2 = cx + r * 0.92 * Math.cos(a), y2 = cy + r * 0.92 * Math.sin(a);
      return `<line x1="${x1.toFixed(1)}" y1="${y1.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${y2.toFixed(1)}" stroke="${hexToRgba('#ffffff', 0.12)}" stroke-width="0.8"/>`;
    }).join('');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <radialGradient id="${uid}-ck-bg" cx="42%" cy="38%"><stop offset="0%" stop-color="${lighten(body, 0.2)}"/><stop offset="100%" stop-color="${darken(body, 0.3)}"/></radialGradient>
  </defs>
  <circle cx="${cx}" cy="${cy}" r="${r}" fill="url(#${uid}-ck-bg)" stroke="${darken(body, 0.45)}" stroke-width="1.5"/>
  ${knurls}
  <circle cx="${cx}" cy="${cy}" r="${r * 0.25}" fill="${darken(body, 0.15)}" stroke="${hexToRgba(accent, 0.3)}" stroke-width="0.5"/>
  <circle cx="${cx}" cy="${cy}" r="${r * 0.08}" fill="${accent}"/>
  <g id="rotate"><line x1="${cx}" y1="${cy}" x2="${cx}" y2="${cy - r + 4}" stroke="${indicator}" stroke-width="2" stroke-linecap="round"/></g>
</svg>`;
  },

  'encoder-notch': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 2;
    // Notch marks around ring
    const notches = Array.from({ length: 20 }, (_, i) => {
      const a = (Math.PI * 2 / 20) * i;
      const x1 = cx + r * 0.88 * Math.cos(a), y1 = cy + r * 0.88 * Math.sin(a);
      const x2 = cx + r * 0.98 * Math.cos(a), y2 = cy + r * 0.98 * Math.sin(a);
      return `<line x1="${x1.toFixed(1)}" y1="${y1.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${y2.toFixed(1)}" stroke="${hexToRgba(accent, 0.4)}" stroke-width="1"/>`;
    }).join('');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <circle cx="${cx}" cy="${cy}" r="${r}" fill="${darken(body, 0.2)}" stroke="${hexToRgba(accent, 0.25)}" stroke-width="1"/>
  ${notches}
  <circle cx="${cx}" cy="${cy}" r="${r * 0.6}" fill="${body}" stroke="${hexToRgba(accent, 0.2)}" stroke-width="0.8"/>
  <circle cx="${cx}" cy="${cy}" r="${r * 0.15}" fill="${hexToRgba(indicator, 0.5)}" stroke="${hexToRgba(indicator, 0.3)}" stroke-width="0.5"/>
  <g id="rotate"><line x1="${cx}" y1="${cy}" x2="${cx}" y2="${cy - r * 0.5}" stroke="${indicator}" stroke-width="2" stroke-linecap="round"/></g>
</svg>`;
  },

  'vu-needle': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h * 0.65, r = Math.min(w, h) * 0.42;
    // Scale marks
    const marks = Array.from({ length: 11 }, (_, i) => {
      const frac = i / 10;
      const a = Math.PI + frac * Math.PI;
      const x1 = cx + (r + 2) * Math.cos(a), y1 = cy + (r + 2) * Math.sin(a);
      const x2 = cx + (r - 3) * Math.cos(a), y2 = cy + (r - 3) * Math.sin(a);
      return `<line x1="${x1.toFixed(1)}" y1="${y1.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${y2.toFixed(1)}" stroke="${hexToRgba(accent, 0.5)}" stroke-width="${i % 5 === 0 ? '1.2' : '0.6'}"/>`;
    }).join('');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <rect x="1" y="1" width="${w - 2}" height="${h - 2}" rx="4" fill="${body}" stroke="${hexToRgba(accent, 0.25)}" stroke-width="1"/>
  <path d="M ${cx - r - 4} ${cy} A ${r + 4} ${r + 4} 0 0 1 ${cx + r + 4} ${cy}" fill="none" stroke="${hexToRgba(accent, 0.15)}" stroke-width="0.5"/>
  ${marks}
  <circle cx="${cx}" cy="${cy}" r="3" fill="${accent}"/>
  <g id="rotate"><line x1="${cx}" y1="${cy}" x2="${cx}" y2="${cy - r}" stroke="${indicator}" stroke-width="1.5" stroke-linecap="round"/></g>
</svg>`;
  },

  'joystick-knob': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 2;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <radialGradient id="${uid}-jk-bg" cx="40%" cy="35%"><stop offset="0%" stop-color="${lighten(body, 0.35)}"/><stop offset="60%" stop-color="${body}"/><stop offset="100%" stop-color="${darken(body, 0.25)}"/></radialGradient>
    <radialGradient id="${uid}-jk-top" cx="35%" cy="30%"><stop offset="0%" stop-color="${lighten(body, 0.45)}"/><stop offset="100%" stop-color="${lighten(body, 0.1)}"/></radialGradient>
  </defs>
  <circle cx="${cx}" cy="${cy}" r="${r}" fill="${darken(body, 0.35)}" stroke="${hexToRgba(accent, 0.2)}" stroke-width="1"/>
  <circle cx="${cx}" cy="${cy}" r="${r * 0.85}" fill="url(#${uid}-jk-bg)" stroke="${darken(body, 0.3)}" stroke-width="0.8"/>
  <circle cx="${cx}" cy="${cy}" r="${r * 0.5}" fill="url(#${uid}-jk-top)" stroke="${hexToRgba('#ffffff', 0.1)}" stroke-width="0.5"/>
  <g id="rotate"><circle cx="${cx}" cy="${cy - r * 0.35}" r="${r * 0.08}" fill="${indicator}"/></g>
</svg>`;
  },

  // ── MOOG-SPECIFIC KNOB STYLES ──────────────────────────────────────────

  'moog-pointer': (w, h, body, indicator, accent, uid) => {
    // Photorealistic Moog pointer knob — Flux-generated image embedded in SVG.
    // Cream skirt with raised triangular pointer, dark center, numbered markings.
    // The entire image rotates via <g id="rotate">.
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 2;
    const imgSize = r * 2;
    // Scale marks on the outer ring (270° arc) — static, don't rotate
    const ticks = Array.from({ length: 11 }, (_, i) => {
      const frac = i / 10;
      const angle = (-225 + frac * 270) * Math.PI / 180;
      const outerR = Math.min(w, h) / 2 - 0.5;
      const x1 = cx + outerR * Math.cos(angle), y1 = cy + outerR * Math.sin(angle);
      const x2 = cx + (outerR - 3) * Math.cos(angle), y2 = cy + (outerR - 3) * Math.sin(angle);
      const isMajor = i % 5 === 0;
      return `<line x1="${x1.toFixed(1)}" y1="${y1.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${y2.toFixed(1)}" stroke="${hexToRgba('#bebebe', isMajor ? 0.5 : 0.25)}" stroke-width="${isMajor ? '0.8' : '0.4'}"/>`;
    }).join('\n  ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  ${ticks}
  <g id="rotate">
    <image xlink:href="${MOOG_POINTER_IMG}" x="${cx - imgSize / 2}" y="${cy - imgSize / 2}" width="${imgSize}" height="${imgSize}"/>
  </g>
</svg>`;
  },

  'moog-round': (w, h, body, indicator, accent, uid) => {
    // Photorealistic Moog round knob — specular handled by CSS overlay in renderer.
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 2;
    const imgSize = r * 2;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <g id="rotate">
    <image xlink:href="${MOOG_ROUND_IMG}" x="${cx - imgSize / 2}" y="${cy - imgSize / 2}" width="${imgSize}" height="${imgSize}"/>
  </g>
</svg>`;
  },

  'moog-octave': (w, h, body, indicator, accent, uid) => {
    // Moog octave/range selector — specular handled by CSS overlay in renderer.
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 2;
    const imgSize = r * 2;
    // 6 position markers (static, outside the rotating group)
    const positions = Array.from({ length: 6 }, (_, i) => {
      const frac = i / 5;
      const angle = (-225 + frac * 270) * Math.PI / 180;
      const markerR = Math.min(w, h) / 2 - 0.5;
      const x = cx + markerR * Math.cos(angle), y = cy + markerR * Math.sin(angle);
      return `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="1.5" fill="#bebebe" opacity="0.5"/>`;
    }).join('\n  ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  ${positions}
  <g id="rotate">
    <image xlink:href="${MOOG_POINTER_IMG}" x="${cx - imgSize / 2}" y="${cy - imgSize / 2}" width="${imgSize}" height="${imgSize}"/>
  </g>
</svg>`;
  },

  'flux': (w, h, body, indicator, accent, uid) => {
    // Placeholder for Flux-generated knob — replaced async by CanvasComponent.
    const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 2;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <g id="rotate">
    <circle cx="${cx}" cy="${cy}" r="${r * 0.8}" fill="#222" stroke="#444" stroke-width="1"/>
    <circle cx="${cx}" cy="${cy}" r="3" fill="#666">
      <animate attributeName="opacity" values="0.4;1;0.4" dur="1.5s" repeatCount="indefinite"/>
    </circle>
  </g>
</svg>`;
  },
};

// ═══════════════════════════════════════════════════════
// SLIDER GENERATORS (5 styles)
// ═══════════════════════════════════════════════════════

const sliderGenerators = {
  'channel-fader': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2;
    const trackW = w * 0.16;
    const thumbW = w * 0.75;
    const thumbH = h * 0.13;
    // dB scale marks
    const marks = Array.from({ length: 11 }, (_, i) => {
      const y = h * 0.06 + (h * 0.88) * (i / 10);
      const isMajor = i % 5 === 0;
      return `<line x1="${cx - trackW}" y1="${y.toFixed(1)}" x2="${cx - trackW - (isMajor ? 5 : 3)}" y2="${y.toFixed(1)}" stroke="${hexToRgba('#ffffff', isMajor ? 0.3 : 0.12)}" stroke-width="${isMajor ? '0.7' : '0.4'}"/>`;
    }).join('\n  ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <linearGradient id="${uid}-cf-trk" x1="0" y1="0" x2="1" y2="0"><stop offset="0%" stop-color="${darken(body, 0.5)}"/><stop offset="50%" stop-color="${darken(body, 0.25)}"/><stop offset="100%" stop-color="${darken(body, 0.5)}"/></linearGradient>
    <linearGradient id="${uid}-cf-thb" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="${lighten(accent, 0.35)}"/><stop offset="30%" stop-color="${lighten(accent, 0.1)}"/><stop offset="70%" stop-color="${accent}"/><stop offset="100%" stop-color="${darken(accent, 0.3)}"/></linearGradient>
    <filter id="${uid}-cf-sh"><feDropShadow dx="0" dy="1" stdDeviation="1.5" flood-color="#000" flood-opacity="0.4"/></filter>
  </defs>
  <rect x="${cx - trackW / 2}" y="${h * 0.04}" width="${trackW}" height="${h * 0.92}" rx="${trackW / 2}" fill="url(#${uid}-cf-trk)" stroke="${hexToRgba(body, 0.25)}" stroke-width="0.5"/>
  <rect x="${cx - trackW * 0.25}" y="${h * 0.04}" width="${trackW * 0.5}" height="${h * 0.92}" rx="${trackW * 0.25}" fill="${hexToRgba('#000000', 0.35)}"/>
  ${marks}
  <g id="thumb">
    <rect x="${cx - thumbW / 2}" y="${h * 0.43}" width="${thumbW}" height="${thumbH}" rx="3" fill="url(#${uid}-cf-thb)" stroke="${darken(accent, 0.35)}" stroke-width="0.8" filter="url(#${uid}-cf-sh)"/>
    <line x1="${cx - thumbW * 0.28}" y1="${h * 0.495}" x2="${cx + thumbW * 0.28}" y2="${h * 0.495}" stroke="${hexToRgba('#ffffff', 0.4)}" stroke-width="1"/>
    <line x1="${cx - thumbW * 0.22}" y1="${h * 0.485}" x2="${cx + thumbW * 0.22}" y2="${h * 0.485}" stroke="${hexToRgba('#ffffff', 0.15)}" stroke-width="0.4"/>
    <line x1="${cx - thumbW * 0.22}" y1="${h * 0.505}" x2="${cx + thumbW * 0.22}" y2="${h * 0.505}" stroke="${hexToRgba('#ffffff', 0.15)}" stroke-width="0.4"/>
  </g>
</svg>`;
  },

  'slot-thumb': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2;
    const slotW = w * 0.25;
    const thumbW = w * 0.8;
    const thumbH = h * 0.1;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <rect x="${cx - slotW / 2}" y="${h * 0.04}" width="${slotW}" height="${h * 0.92}" rx="${slotW / 2}" fill="${darken(body, 0.4)}" stroke="${hexToRgba(accent, 0.2)}" stroke-width="0.5"/>
  <g id="thumb">
    <rect x="${cx - thumbW / 2}" y="${h * 0.45}" width="${thumbW}" height="${thumbH}" rx="2" fill="${body}" stroke="${accent}" stroke-width="0.8"/>
    <line x1="${cx - thumbW * 0.2}" y1="${h * 0.5}" x2="${cx + thumbW * 0.2}" y2="${h * 0.5}" stroke="${hexToRgba('#ffffff', 0.25)}" stroke-width="0.5"/>
    <line x1="${cx - thumbW * 0.2}" y1="${h * 0.475}" x2="${cx + thumbW * 0.2}" y2="${h * 0.475}" stroke="${hexToRgba('#ffffff', 0.15)}" stroke-width="0.5"/>
    <line x1="${cx - thumbW * 0.2}" y1="${h * 0.525}" x2="${cx + thumbW * 0.2}" y2="${h * 0.525}" stroke="${hexToRgba('#ffffff', 0.15)}" stroke-width="0.5"/>
  </g>
</svg>`;
  },

  'led-bar': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2;
    const segW = w * 0.6;
    const segCount = 10;
    const gap = h * 0.01;
    const segH = (h * 0.88 - gap * (segCount - 1)) / segCount;
    const segs = Array.from({ length: segCount }, (_, i) => {
      const y = h * 0.06 + i * (segH + gap);
      const lit = i >= 3;
      return `<rect x="${cx - segW / 2}" y="${y.toFixed(1)}" width="${segW}" height="${segH.toFixed(1)}" rx="1" fill="${indicator}" opacity="${lit ? '0.85' : '0.12'}"/>`;
    }).join('\n  ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <rect x="${cx - segW / 2 - 2}" y="${h * 0.03}" width="${segW + 4}" height="${h * 0.94}" rx="3" fill="${darken(body, 0.3)}" stroke="${hexToRgba(accent, 0.15)}" stroke-width="0.5"/>
  ${segs}
  <g id="thumb"><rect x="${cx - segW / 2 - 2}" y="${h * 0.28}" width="${segW + 4}" height="2" fill="${indicator}" opacity="0"/></g>
</svg>`;
  },

  'minimal-track': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2;
    const dotR = w * 0.15;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <line x1="${cx}" y1="${h * 0.05}" x2="${cx}" y2="${h * 0.95}" stroke="${hexToRgba(accent, 0.25)}" stroke-width="1.5" stroke-linecap="round"/>
  <g id="thumb"><circle cx="${cx}" cy="${h * 0.5}" r="${dotR}" fill="none" stroke="${indicator}" stroke-width="1.5"/><circle cx="${cx}" cy="${h * 0.5}" r="${dotR * 0.35}" fill="${indicator}"/></g>
</svg>`;
  },

  'vintage-slot': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2;
    const slotW = w * 0.22;
    const thumbW = w * 0.72;
    const thumbH = h * 0.12;
    // Scale marks beside the slot
    const marks = Array.from({ length: 11 }, (_, i) => {
      const y = h * 0.06 + (h * 0.88) * (i / 10);
      const isMajor = i % 5 === 0;
      const x1 = cx + slotW / 2 + 3, x2 = x1 + (isMajor ? 5 : 3);
      return `<line x1="${x1.toFixed(1)}" y1="${y.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${y.toFixed(1)}" stroke="${hexToRgba('#ffffff', isMajor ? 0.3 : 0.15)}" stroke-width="${isMajor ? '0.7' : '0.4'}"/>`;
    }).join('\n  ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <linearGradient id="${uid}-vs-slot" x1="0" y1="0" x2="1" y2="0"><stop offset="0%" stop-color="${darken(body, 0.5)}"/><stop offset="50%" stop-color="${darken(body, 0.35)}"/><stop offset="100%" stop-color="${darken(body, 0.5)}"/></linearGradient>
    <linearGradient id="${uid}-vs-thb" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="${lighten(body, 0.25)}"/><stop offset="45%" stop-color="${body}"/><stop offset="100%" stop-color="${darken(body, 0.2)}"/></linearGradient>
    <filter id="${uid}-vs-sh"><feDropShadow dx="0" dy="1" stdDeviation="1.5" flood-color="#000" flood-opacity="0.4"/></filter>
  </defs>
  <rect x="${cx - slotW / 2}" y="${h * 0.04}" width="${slotW}" height="${h * 0.92}" rx="${slotW / 2}" fill="url(#${uid}-vs-slot)" stroke="${hexToRgba(accent, 0.2)}" stroke-width="0.5"/>
  ${marks}
  <g id="thumb">
    <rect x="${cx - thumbW / 2}" y="${h * 0.44}" width="${thumbW}" height="${thumbH}" rx="${thumbH * 0.35}" fill="url(#${uid}-vs-thb)" stroke="${accent}" stroke-width="1" filter="url(#${uid}-vs-sh)"/>
    <line x1="${cx - thumbW * 0.2}" y1="${h * 0.495}" x2="${cx + thumbW * 0.2}" y2="${h * 0.495}" stroke="${hexToRgba('#ffffff', 0.25)}" stroke-width="0.8"/>
    <line x1="${cx - thumbW * 0.15}" y1="${h * 0.51}" x2="${cx + thumbW * 0.15}" y2="${h * 0.51}" stroke="${hexToRgba('#ffffff', 0.12)}" stroke-width="0.4"/>
  </g>
</svg>`;
  },

  'drawbar': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2;
    const barW = w * 0.55;
    const segCount = 8;
    const segH = h * 0.08;
    const gap = (h * 0.8) / segCount;
    const segs = Array.from({ length: segCount }, (_, i) => {
      const y = h * 0.08 + i * gap;
      return `<rect x="${cx - barW / 2}" y="${y.toFixed(1)}" width="${barW}" height="${segH.toFixed(1)}" rx="1" fill="${hexToRgba(accent, 0.15)}" stroke="${hexToRgba(accent, 0.1)}" stroke-width="0.3"/>
  <text x="${cx + barW / 2 + 3}" y="${(y + segH * 0.75).toFixed(1)}" fill="${hexToRgba(accent, 0.35)}" font-size="${Math.max(6, w * 0.12)}" font-family="sans-serif">${8 - i}</text>`;
    }).join('\n  ');
    const thumbH = h * 0.12;
    const thumbW = barW + 6;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <linearGradient id="${uid}-db-thb" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="${lighten(body, 0.2)}"/><stop offset="100%" stop-color="${darken(body, 0.1)}"/></linearGradient>
  </defs>
  <rect x="${cx - barW / 2 - 1}" y="${h * 0.03}" width="${barW + 2}" height="${h * 0.94}" rx="3" fill="${darken(body, 0.3)}" stroke="${hexToRgba(accent, 0.15)}" stroke-width="0.5"/>
  ${segs}
  <g id="thumb">
    <rect x="${cx - thumbW / 2}" y="${h * 0.4}" width="${thumbW}" height="${thumbH}" rx="${thumbH * 0.35}" fill="url(#${uid}-db-thb)" stroke="${accent}" stroke-width="1"/>
  </g>
</svg>`;
  },

  'ribbon': (w, h, body, indicator, accent, uid) => {
    const cy = h / 2;
    const ribbonH = h * 0.08;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <linearGradient id="${uid}-rb-bg" x1="0" y1="0" x2="1" y2="0"><stop offset="0%" stop-color="${darken(body, 0.3)}"/><stop offset="50%" stop-color="${darken(body, 0.15)}"/><stop offset="100%" stop-color="${darken(body, 0.3)}"/></linearGradient>
    <filter id="${uid}-rb-glow"><feGaussianBlur stdDeviation="3" result="blur"/><feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
  </defs>
  <rect x="${w * 0.05}" y="${cy - ribbonH / 2}" width="${w * 0.9}" height="${ribbonH}" rx="${ribbonH / 2}" fill="url(#${uid}-rb-bg)" stroke="${hexToRgba(accent, 0.2)}" stroke-width="0.5"/>
  <g id="thumb">
    <circle cx="${w * 0.5}" cy="${cy}" r="${ribbonH}" fill="${hexToRgba(indicator, 0.4)}" filter="url(#${uid}-rb-glow)"/>
    <circle cx="${w * 0.5}" cy="${cy}" r="${ribbonH * 0.4}" fill="${indicator}"/>
  </g>
</svg>`;
  },

  'crossfader': (w, h, body, indicator, accent, uid) => {
    const cy = h / 2;
    const trackH = h * 0.12;
    const thumbW = w * 0.18;
    const thumbH = h * 0.55;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <linearGradient id="${uid}-xf-thb" x1="0" y1="0" x2="1" y2="0"><stop offset="0%" stop-color="${lighten(accent, 0.2)}"/><stop offset="50%" stop-color="${accent}"/><stop offset="100%" stop-color="${darken(accent, 0.2)}"/></linearGradient>
  </defs>
  <rect x="${w * 0.05}" y="${cy - trackH / 2}" width="${w * 0.9}" height="${trackH}" rx="${trackH / 2}" fill="${darken(body, 0.35)}" stroke="${hexToRgba(accent, 0.2)}" stroke-width="0.5"/>
  <rect x="${w * 0.08}" y="${cy - trackH * 0.2}" width="${w * 0.84}" height="${trackH * 0.4}" rx="${trackH * 0.2}" fill="${hexToRgba('#000000', 0.3)}"/>
  <g id="thumb">
    <rect x="${w * 0.42}" y="${cy - thumbH / 2}" width="${thumbW}" height="${thumbH}" rx="3" fill="url(#${uid}-xf-thb)" stroke="${darken(accent, 0.3)}" stroke-width="0.8"/>
    <line x1="${w * 0.5}" y1="${cy - thumbH * 0.2}" x2="${w * 0.5}" y2="${cy + thumbH * 0.2}" stroke="${hexToRgba('#ffffff', 0.3)}" stroke-width="0.8"/>
  </g>
</svg>`;
  },

  'meter-slider': (w, h, body, indicator, accent, uid) => {
    const cx = w * 0.35;
    const meterX = w * 0.7;
    const trackW = w * 0.12;
    const thumbW = w * 0.5;
    const thumbH = h * 0.1;
    const meterW = w * 0.12;
    const segCount = 10;
    const segH = (h * 0.84) / segCount - 1;
    const segs = Array.from({ length: segCount }, (_, i) => {
      const y = h * 0.06 + i * (segH + 1);
      const lit = i >= 4;
      const color = i < 2 ? '#ff3333' : i < 4 ? '#ffaa00' : indicator;
      return `<rect x="${meterX - meterW / 2}" y="${y.toFixed(1)}" width="${meterW}" height="${segH.toFixed(1)}" rx="0.5" fill="${color}" opacity="${lit ? '0.7' : '0.12'}"/>`;
    }).join('\n  ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <rect x="${cx - trackW / 2}" y="${h * 0.04}" width="${trackW}" height="${h * 0.92}" rx="${trackW / 2}" fill="${darken(body, 0.35)}" stroke="${hexToRgba(accent, 0.15)}" stroke-width="0.5"/>
  ${segs}
  <g id="thumb">
    <rect x="${cx - thumbW / 2}" y="${h * 0.45}" width="${thumbW}" height="${thumbH}" rx="2" fill="${body}" stroke="${accent}" stroke-width="0.8"/>
    <line x1="${cx - thumbW * 0.15}" y1="${h * 0.5}" x2="${cx + thumbW * 0.15}" y2="${h * 0.5}" stroke="${hexToRgba('#ffffff', 0.25)}" stroke-width="0.5"/>
  </g>
</svg>`;
  },

  'notched-slider': (w, h, body, indicator, accent, uid) => {
    const cx = w / 2;
    const trackW = w * 0.12;
    const thumbW = w * 0.7;
    const thumbH = h * 0.08;
    // Center notch marks
    const notches = Array.from({ length: 11 }, (_, i) => {
      const y = h * 0.06 + (h * 0.88) * (i / 10);
      const isCenter = i === 5;
      return `<line x1="${cx - trackW}" y1="${y.toFixed(1)}" x2="${cx + trackW}" y2="${y.toFixed(1)}" stroke="${hexToRgba(accent, isCenter ? 0.6 : 0.25)}" stroke-width="${isCenter ? '1' : '0.5'}"/>`;
    }).join('\n  ');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <rect x="${cx - trackW / 2}" y="${h * 0.04}" width="${trackW}" height="${h * 0.92}" rx="${trackW / 2}" fill="${darken(body, 0.3)}" stroke="${hexToRgba(accent, 0.2)}" stroke-width="0.5"/>
  ${notches}
  <g id="thumb">
    <rect x="${cx - thumbW / 2}" y="${h * 0.47}" width="${thumbW}" height="${thumbH}" rx="2" fill="${body}" stroke="${indicator}" stroke-width="1"/>
    <circle cx="${cx}" cy="${h * 0.505}" r="${thumbH * 0.2}" fill="${indicator}"/>
  </g>
</svg>`;
  },

  'flux': (w, h, body, indicator, accent, uid) => {
    // Placeholder for Flux-generated slider — replaced async by CanvasComponent.
    const cx = w / 2;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <rect x="${cx - 3}" y="8" width="6" height="${h - 16}" rx="3" fill="#222" stroke="#444" stroke-width="0.5"/>
  <g id="thumb">
    <rect x="${cx - 10}" y="${h / 2 - 8}" width="20" height="16" rx="3" fill="#555" stroke="#666" stroke-width="0.5">
      <animate attributeName="opacity" values="0.5;1;0.5" dur="1.5s" repeatCount="indefinite"/>
    </rect>
  </g>
</svg>`;
  },
};

// ═══════════════════════════════════════════════════════
// BUTTON GENERATORS (5 styles)
// ═══════════════════════════════════════════════════════

const buttonGenerators = {
  'toggle-led': (w, h, body, indicator, accent, uid, label) => {
    const ledR = Math.min(h * 0.15, 4);
    const ledX = ledR + 6;
    const textX = ledX + ledR + 6;
    const safeLabel = escapeXml(label);
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs><filter id="${uid}-tl-glow"><feGaussianBlur stdDeviation="1.5" result="blur"/><feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs>
  <g id="normal">
    <rect x="1" y="1" width="${w - 2}" height="${h - 2}" rx="4" fill="${body}" stroke="${hexToRgba(accent, 0.3)}" stroke-width="0.8"/>
    <circle cx="${ledX}" cy="${h / 2}" r="${ledR}" fill="${indicator}" opacity="0.25"/>
    <text x="${textX}" y="${h * 0.62}" fill="${hexToRgba('#ffffff', 0.45)}" font-size="${Math.min(11, h * 0.4)}" font-family="sans-serif">${safeLabel}</text>
  </g>
  <g id="pressed" display="none">
    <rect x="1" y="1" width="${w - 2}" height="${h - 2}" rx="4" fill="${lighten(body, 0.08)}" stroke="${hexToRgba(indicator, 0.4)}" stroke-width="0.8"/>
    <circle cx="${ledX}" cy="${h / 2}" r="${ledR}" fill="${indicator}" filter="url(#${uid}-tl-glow)"/>
    <text x="${textX}" y="${h * 0.62}" fill="${hexToRgba('#ffffff', 0.9)}" font-size="${Math.min(11, h * 0.4)}" font-weight="bold" font-family="sans-serif">${safeLabel}</text>
  </g>
</svg>`;
  },

  'rocker': (w, h, body, indicator, accent, uid, label) => {
    const safeLabel = escapeXml(label);
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <linearGradient id="${uid}-rk-up" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="${lighten(body, 0.25)}"/><stop offset="100%" stop-color="${darken(body, 0.15)}"/></linearGradient>
    <linearGradient id="${uid}-rk-dn" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="${darken(body, 0.15)}"/><stop offset="100%" stop-color="${lighten(body, 0.15)}"/></linearGradient>
  </defs>
  <g id="normal">
    <rect x="1" y="1" width="${w - 2}" height="${h - 2}" rx="3" fill="url(#${uid}-rk-up)" stroke="${darken(body, 0.4)}" stroke-width="1"/>
    <text x="${w / 2}" y="${h * 0.62}" text-anchor="middle" fill="${hexToRgba('#ffffff', 0.55)}" font-size="${Math.min(10, h * 0.38)}" font-family="sans-serif">${safeLabel}</text>
  </g>
  <g id="pressed" display="none">
    <rect x="1" y="1" width="${w - 2}" height="${h - 2}" rx="3" fill="url(#${uid}-rk-dn)" stroke="${darken(body, 0.4)}" stroke-width="1"/>
    <rect x="2" y="2" width="${w - 4}" height="${h - 4}" rx="2" fill="${hexToRgba('#000000', 0.1)}"/>
    <text x="${w / 2}" y="${h * 0.62}" text-anchor="middle" fill="${hexToRgba('#ffffff', 0.8)}" font-size="${Math.min(10, h * 0.38)}" font-family="sans-serif">${safeLabel}</text>
  </g>
</svg>`;
  },

  'momentary': (w, h, body, indicator, accent, uid, label) => {
    const cx = w / 2, cy = h / 2;
    const r = Math.min(w, h) / 2 - 2;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <radialGradient id="${uid}-mo-up" cx="40%" cy="35%"><stop offset="0%" stop-color="${lighten(body, 0.25)}"/><stop offset="100%" stop-color="${darken(body, 0.2)}"/></radialGradient>
    <radialGradient id="${uid}-mo-dn" cx="50%" cy="55%"><stop offset="0%" stop-color="${lighten(body, 0.1)}"/><stop offset="100%" stop-color="${darken(body, 0.3)}"/></radialGradient>
  </defs>
  <g id="normal">
    <circle cx="${cx}" cy="${cy}" r="${r}" fill="url(#${uid}-mo-up)" stroke="${darken(body, 0.4)}" stroke-width="1"/>
    <circle cx="${cx}" cy="${cy}" r="${r * 0.7}" fill="none" stroke="${hexToRgba('#ffffff', 0.08)}" stroke-width="0.5"/>
  </g>
  <g id="pressed" display="none">
    <circle cx="${cx}" cy="${cy}" r="${r}" fill="url(#${uid}-mo-dn)" stroke="${darken(body, 0.4)}" stroke-width="1"/>
    <circle cx="${cx}" cy="${cy}" r="${r * 0.7}" fill="${hexToRgba(indicator, 0.15)}"/>
  </g>
</svg>`;
  },

  'pill-glow': (w, h, body, indicator, accent, uid, label) => {
    const safeLabel = escapeXml(label);
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs><filter id="${uid}-pg-glow"><feGaussianBlur stdDeviation="2" result="blur"/><feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs>
  <g id="normal">
    <rect x="1" y="1" width="${w - 2}" height="${h - 2}" rx="${h / 2}" fill="${body}" stroke="${hexToRgba(accent, 0.2)}" stroke-width="0.8"/>
    <text x="${w / 2}" y="${h * 0.62}" text-anchor="middle" fill="${hexToRgba('#ffffff', 0.45)}" font-size="${Math.min(11, h * 0.4)}" font-family="sans-serif">${safeLabel}</text>
  </g>
  <g id="pressed" display="none">
    <rect x="1" y="1" width="${w - 2}" height="${h - 2}" rx="${h / 2}" fill="${hexToRgba(indicator, 0.15)}" stroke="${hexToRgba(indicator, 0.5)}" stroke-width="1" filter="url(#${uid}-pg-glow)"/>
    <text x="${w / 2}" y="${h * 0.62}" text-anchor="middle" fill="#fff" font-size="${Math.min(11, h * 0.4)}" font-weight="bold" font-family="sans-serif">${safeLabel}</text>
  </g>
</svg>`;
  },

  'vintage-toggle': (w, h, body, indicator, accent, uid, label) => {
    const cx = w / 2;
    const leverW = w * 0.13;
    const baseH = h * 0.38;
    const plateW = w * 0.44;
    const plateH = h * 0.65;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <linearGradient id="${uid}-vt-lv" x1="0" y1="0" x2="1" y2="0"><stop offset="0%" stop-color="${lighten(accent, 0.35)}"/><stop offset="30%" stop-color="${lighten(accent, 0.15)}"/><stop offset="70%" stop-color="${accent}"/><stop offset="100%" stop-color="${darken(accent, 0.25)}"/></linearGradient>
    <linearGradient id="${uid}-vt-plt" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="${lighten(body, 0.05)}"/><stop offset="100%" stop-color="${darken(body, 0.25)}"/></linearGradient>
    <filter id="${uid}-vt-sh"><feDropShadow dx="0" dy="1" stdDeviation="1.5" flood-color="#000" flood-opacity="0.45"/></filter>
  </defs>
  <g id="normal">
    <rect x="${cx - plateW / 2}" y="${(h - plateH) / 2}" width="${plateW}" height="${plateH}" rx="4" fill="url(#${uid}-vt-plt)" stroke="${darken(body, 0.35)}" stroke-width="1"/>
    <rect x="${cx - plateW / 2 + 2}" y="${(h - plateH) / 2 + 2}" width="${plateW - 4}" height="${plateH - 4}" rx="2" fill="none" stroke="${hexToRgba('#ffffff', 0.04)}" stroke-width="0.5"/>
    <rect x="${cx - leverW / 2}" y="${h * 0.46}" width="${leverW}" height="${baseH}" rx="${leverW / 2}" fill="url(#${uid}-vt-lv)" filter="url(#${uid}-vt-sh)"/>
    <circle cx="${cx}" cy="${h * 0.46 + leverW / 2}" r="${leverW * 0.55}" fill="${lighten(accent, 0.45)}"/>
    <ellipse cx="${cx}" cy="${h * 0.46 + leverW * 0.3}" rx="${leverW * 0.2}" ry="${leverW * 0.15}" fill="${hexToRgba('#ffffff', 0.25)}"/>
  </g>
  <g id="pressed" display="none">
    <rect x="${cx - plateW / 2}" y="${(h - plateH) / 2}" width="${plateW}" height="${plateH}" rx="4" fill="url(#${uid}-vt-plt)" stroke="${hexToRgba(indicator, 0.35)}" stroke-width="1"/>
    <rect x="${cx - plateW / 2 + 2}" y="${(h - plateH) / 2 + 2}" width="${plateW - 4}" height="${plateH - 4}" rx="2" fill="none" stroke="${hexToRgba('#ffffff', 0.04)}" stroke-width="0.5"/>
    <rect x="${cx - leverW / 2}" y="${h * 0.2}" width="${leverW}" height="${baseH}" rx="${leverW / 2}" fill="url(#${uid}-vt-lv)" filter="url(#${uid}-vt-sh)"/>
    <circle cx="${cx}" cy="${h * 0.2 + baseH - leverW / 2}" r="${leverW * 0.55}" fill="${lighten(accent, 0.45)}"/>
    <ellipse cx="${cx}" cy="${h * 0.2 + baseH - leverW * 0.65}" rx="${leverW * 0.2}" ry="${leverW * 0.15}" fill="${hexToRgba('#ffffff', 0.25)}"/>
  </g>
</svg>`;
  },

  'arcade-button': (w, h, body, indicator, accent, uid, label) => {
    const cx = w / 2, cy = h / 2;
    const r = Math.min(w, h) / 2 - 2;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <radialGradient id="${uid}-ab-up" cx="40%" cy="35%"><stop offset="0%" stop-color="${lighten(indicator, 0.4)}"/><stop offset="60%" stop-color="${indicator}"/><stop offset="100%" stop-color="${darken(indicator, 0.3)}"/></radialGradient>
    <radialGradient id="${uid}-ab-dn" cx="50%" cy="55%"><stop offset="0%" stop-color="${lighten(indicator, 0.2)}"/><stop offset="100%" stop-color="${darken(indicator, 0.4)}"/></radialGradient>
  </defs>
  <g id="normal">
    <circle cx="${cx}" cy="${cy}" r="${r}" fill="${darken(body, 0.3)}" stroke="${darken(body, 0.5)}" stroke-width="2"/>
    <circle cx="${cx}" cy="${cy}" r="${r * 0.82}" fill="url(#${uid}-ab-up)" stroke="${darken(indicator, 0.2)}" stroke-width="1"/>
    <circle cx="${cx}" cy="${cy * 0.85}" r="${r * 0.15}" fill="${hexToRgba('#ffffff', 0.3)}"/>
  </g>
  <g id="pressed" display="none">
    <circle cx="${cx}" cy="${cy}" r="${r}" fill="${darken(body, 0.3)}" stroke="${darken(body, 0.5)}" stroke-width="2"/>
    <circle cx="${cx}" cy="${cy}" r="${r * 0.78}" fill="url(#${uid}-ab-dn)" stroke="${darken(indicator, 0.3)}" stroke-width="1"/>
  </g>
</svg>`;
  },

  'radio-button': (w, h, body, indicator, accent, uid, label) => {
    const cx = w / 2, cy = h / 2;
    const r = Math.min(w, h) / 2 - 3;
    const safeLabel = escapeXml(label);
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <g id="normal">
    <circle cx="${r + 4}" cy="${cy}" r="${r}" fill="none" stroke="${hexToRgba(accent, 0.4)}" stroke-width="1.5"/>
    <text x="${r * 2 + 10}" y="${cy + 4}" fill="${hexToRgba('#ffffff', 0.5)}" font-size="${Math.min(11, h * 0.4)}" font-family="sans-serif">${safeLabel}</text>
  </g>
  <g id="pressed" display="none">
    <circle cx="${r + 4}" cy="${cy}" r="${r}" fill="none" stroke="${indicator}" stroke-width="1.5"/>
    <circle cx="${r + 4}" cy="${cy}" r="${r * 0.5}" fill="${indicator}"/>
    <text x="${r * 2 + 10}" y="${cy + 4}" fill="${hexToRgba('#ffffff', 0.9)}" font-size="${Math.min(11, h * 0.4)}" font-family="sans-serif">${safeLabel}</text>
  </g>
</svg>`;
  },

  'footswitch': (w, h, body, indicator, accent, uid, label) => {
    const cx = w / 2, cy = h / 2;
    const rOuter = Math.min(w, h) / 2 - 2;
    const rInner = rOuter * 0.7;
    // Textured dots
    const dots = Array.from({ length: 8 }, (_, i) => {
      const a = (Math.PI * 2 / 8) * i;
      const x = cx + rInner * 0.55 * Math.cos(a), y = cy + rInner * 0.55 * Math.sin(a);
      return `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="1" fill="${hexToRgba('#ffffff', 0.08)}"/>`;
    }).join('');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <g id="normal">
    <circle cx="${cx}" cy="${cy}" r="${rOuter}" fill="${darken(body, 0.3)}" stroke="${darken(body, 0.5)}" stroke-width="2"/>
    <circle cx="${cx}" cy="${cy}" r="${rInner}" fill="${body}" stroke="${hexToRgba(accent, 0.2)}" stroke-width="1"/>
    ${dots}
    <circle cx="${cx}" cy="${cy}" r="${rOuter * 0.12}" fill="${indicator}" opacity="0.3"/>
  </g>
  <g id="pressed" display="none">
    <circle cx="${cx}" cy="${cy}" r="${rOuter}" fill="${darken(body, 0.35)}" stroke="${darken(body, 0.5)}" stroke-width="2"/>
    <circle cx="${cx}" cy="${cy}" r="${rInner - 1}" fill="${darken(body, 0.05)}" stroke="${hexToRgba(accent, 0.3)}" stroke-width="1"/>
    ${dots}
    <circle cx="${cx}" cy="${cy}" r="${rOuter * 0.12}" fill="${indicator}" opacity="1"/>
  </g>
</svg>`;
  },

  'backlit-label': (w, h, body, indicator, accent, uid, label) => {
    const safeLabel = escapeXml(label);
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs><filter id="${uid}-bl-glow"><feGaussianBlur stdDeviation="1" result="blur"/><feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs>
  <g id="normal">
    <rect x="1" y="1" width="${w - 2}" height="${h - 2}" rx="2" fill="${darken(body, 0.2)}" stroke="${hexToRgba(accent, 0.15)}" stroke-width="0.8"/>
    <text x="${w / 2}" y="${h * 0.62}" text-anchor="middle" fill="${hexToRgba(indicator, 0.35)}" font-size="${Math.min(11, h * 0.4)}" font-family="sans-serif">${safeLabel}</text>
  </g>
  <g id="pressed" display="none">
    <rect x="1" y="1" width="${w - 2}" height="${h - 2}" rx="2" fill="${hexToRgba(indicator, 0.08)}" stroke="${hexToRgba(indicator, 0.3)}" stroke-width="0.8"/>
    <text x="${w / 2}" y="${h * 0.62}" text-anchor="middle" fill="${indicator}" font-size="${Math.min(11, h * 0.4)}" font-weight="bold" font-family="sans-serif" filter="url(#${uid}-bl-glow)">${safeLabel}</text>
  </g>
</svg>`;
  },

  'rotary-switch': (w, h, body, indicator, accent, uid, label) => {
    const cx = w / 2, cy = h / 2;
    const r = Math.min(w, h) / 2 - 2;
    // Position markers
    const positions = Array.from({ length: 5 }, (_, i) => {
      const frac = i / 4;
      const a = (-135 + frac * 270) * Math.PI / 180;
      const x = cx + (r + 1) * Math.cos(a), y = cy + (r + 1) * Math.sin(a);
      return `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="1.5" fill="${hexToRgba(accent, 0.5)}"/>`;
    }).join('');
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <radialGradient id="${uid}-rs-bg" cx="45%" cy="40%"><stop offset="0%" stop-color="${lighten(body, 0.15)}"/><stop offset="100%" stop-color="${darken(body, 0.25)}"/></radialGradient>
  </defs>
  <g id="normal">
    ${positions}
    <circle cx="${cx}" cy="${cy}" r="${r * 0.8}" fill="url(#${uid}-rs-bg)" stroke="${hexToRgba(accent, 0.3)}" stroke-width="1"/>
    <line x1="${cx}" y1="${cy}" x2="${cx}" y2="${cy - r * 0.6}" stroke="${indicator}" stroke-width="2.5" stroke-linecap="round"/>
    <circle cx="${cx}" cy="${cy}" r="${r * 0.15}" fill="${darken(body, 0.15)}"/>
  </g>
  <g id="pressed" display="none">
    ${positions}
    <circle cx="${cx}" cy="${cy}" r="${r * 0.8}" fill="url(#${uid}-rs-bg)" stroke="${hexToRgba(indicator, 0.4)}" stroke-width="1"/>
    <line x1="${cx}" y1="${cy}" x2="${cx + r * 0.42}" y2="${cy - r * 0.42}" stroke="${indicator}" stroke-width="2.5" stroke-linecap="round"/>
    <circle cx="${cx}" cy="${cy}" r="${r * 0.15}" fill="${darken(body, 0.15)}"/>
  </g>
</svg>`;
  },

  'moog-rocker': (w, h, body, indicator, accent, uid, label) => {
    // Authentic Moog rocker switch: rectangular cream/black toggle with rounded corners
    // Found on Minimoog, Model D — on/off or mode selection
    const safeLabel = escapeXml(label);
    const cream = '#E8DFC8';
    const creamDark = '#C8BFA8';
    const cx = w / 2;
    const plateW = w * 0.52;
    const plateH = h * 0.72;
    const rockerW = plateW - 4;
    const rockerH = plateH * 0.42;
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <linearGradient id="${uid}-mrkr-plate" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="#2a2520"/><stop offset="100%" stop-color="#1a1612"/></linearGradient>
    <linearGradient id="${uid}-mrkr-up" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="#F5F0E0"/><stop offset="30%" stop-color="${cream}"/><stop offset="70%" stop-color="${creamDark}"/><stop offset="100%" stop-color="#A89E88"/></linearGradient>
    <linearGradient id="${uid}-mrkr-dn" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="#A89E88"/><stop offset="30%" stop-color="${creamDark}"/><stop offset="70%" stop-color="${cream}"/><stop offset="100%" stop-color="#F5F0E0"/></linearGradient>
    <filter id="${uid}-mrkr-sh"><feDropShadow dx="0" dy="1" stdDeviation="1.2" flood-color="#000" flood-opacity="0.5"/></filter>
  </defs>
  <g id="normal">
    <rect x="${cx - plateW / 2}" y="${(h - plateH) / 2}" width="${plateW}" height="${plateH}" rx="3" fill="url(#${uid}-mrkr-plate)" stroke="#0e0c0a" stroke-width="1"/>
    <rect x="${cx - plateW / 2 + 1}" y="${(h - plateH) / 2 + 1}" width="${plateW - 2}" height="${plateH - 2}" rx="2" fill="none" stroke="${hexToRgba('#ffffff', 0.04)}" stroke-width="0.5"/>
    <rect x="${cx - rockerW / 2}" y="${(h - plateH) / 2 + plateH - rockerH - 3}" width="${rockerW}" height="${rockerH}" rx="2" fill="url(#${uid}-mrkr-up)" stroke="${creamDark}" stroke-width="0.8" filter="url(#${uid}-mrkr-sh)"/>
    <line x1="${cx - rockerW * 0.25}" y1="${(h - plateH) / 2 + plateH - rockerH * 0.5 - 3}" x2="${cx + rockerW * 0.25}" y2="${(h - plateH) / 2 + plateH - rockerH * 0.5 - 3}" stroke="${hexToRgba('#ffffff', 0.2)}" stroke-width="0.5"/>
  </g>
  <g id="pressed" display="none">
    <rect x="${cx - plateW / 2}" y="${(h - plateH) / 2}" width="${plateW}" height="${plateH}" rx="3" fill="url(#${uid}-mrkr-plate)" stroke="#0e0c0a" stroke-width="1"/>
    <rect x="${cx - plateW / 2 + 1}" y="${(h - plateH) / 2 + 1}" width="${plateW - 2}" height="${plateH - 2}" rx="2" fill="none" stroke="${hexToRgba('#ffffff', 0.04)}" stroke-width="0.5"/>
    <rect x="${cx - rockerW / 2}" y="${(h - plateH) / 2 + 3}" width="${rockerW}" height="${rockerH}" rx="2" fill="url(#${uid}-mrkr-dn)" stroke="${creamDark}" stroke-width="0.8" filter="url(#${uid}-mrkr-sh)"/>
    <line x1="${cx - rockerW * 0.25}" y1="${(h - plateH) / 2 + rockerH * 0.5 + 3}" x2="${cx + rockerW * 0.25}" y2="${(h - plateH) / 2 + rockerH * 0.5 + 3}" stroke="${hexToRgba('#ffffff', 0.2)}" stroke-width="0.5"/>
  </g>
</svg>`;
  },

  // ── Flux (AI-generated photorealistic) ──
  'flux': (w, h, body, indicator, accent, uid, label) => {
    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <g id="normal">
    <rect x="2" y="2" width="${w - 4}" height="${h - 4}" rx="4" fill="#333" stroke="#555" stroke-width="0.5"/>
    <circle cx="${w / 2}" cy="${h / 2}" r="3" fill="#666">
      <animate attributeName="opacity" values="0.4;1;0.4" dur="1.5s" repeatCount="indefinite"/>
    </circle>
  </g>
  <g id="pressed" display="none">
    <rect x="2" y="2" width="${w - 4}" height="${h - 4}" rx="4" fill="#444" stroke="#666" stroke-width="0.5"/>
  </g>
</svg>`;
  },
};

// ═══════════════════════════════════════════════════════
// PUBLIC API
// ═══════════════════════════════════════════════════════

export function generateKnobSVG(style, { width = 60, height = 60, bodyColor = '#333', indicatorColor = '#fff', accentColor = '#888', uid = 'k' }) {
  const gen = knobGenerators[style] || knobGenerators['dome-line'];
  return gen(width, height, bodyColor, indicatorColor, accentColor, uid);
}

export function generateSliderSVG(style, { width = 30, height = 120, bodyColor = '#333', indicatorColor = '#fff', accentColor = '#888', uid = 's' }) {
  const gen = sliderGenerators[style] || sliderGenerators['channel-fader'];
  return gen(width, height, bodyColor, indicatorColor, accentColor, uid);
}

export function generateButtonSVG(style, { width = 70, height = 28, bodyColor = '#1a1a2e', indicatorColor = '#667eea', accentColor = '#888', uid = 'b', label = '' }) {
  const gen = buttonGenerators[style] || buttonGenerators['toggle-led'];
  return gen(width, height, bodyColor, indicatorColor, accentColor, uid, label);
}

// ═══════════════════════════════════════════════════════
// FLUX BUILDER HELPERS — inject base64 images into SVGs
// ═══════════════════════════════════════════════════════

export function buildFluxKnobSVG(w, h, diffuseUrl, specularUrl) {
  const cx = w / 2, cy = h / 2, r = Math.min(w, h) / 2 - 2;
  const imgSize = r * 2;
  const specularLayer = specularUrl
    ? `\n  <image xlink:href="${specularUrl}" x="${cx - imgSize / 2}" y="${cy - imgSize / 2}" width="${imgSize}" height="${imgSize}" pointer-events="none"/>`
    : '';
  return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <g id="rotate">
    <image xlink:href="${diffuseUrl}" x="${cx - imgSize / 2}" y="${cy - imgSize / 2}" width="${imgSize}" height="${imgSize}"/>
  </g>${specularLayer}
</svg>`;
}

export function buildFluxSliderSVG(w, h, trackDataUrl, thumbDataUrl) {
  const cx = w / 2;
  const trackW = w * 0.4, trackH = h - 16;
  const thumbW = w * 0.7, thumbH = 20;
  return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <image xlink:href="${trackDataUrl}" x="${cx - trackW / 2}" y="8" width="${trackW}" height="${trackH}" preserveAspectRatio="none"/>
  <g id="thumb">
    <image xlink:href="${thumbDataUrl}" x="${cx - thumbW / 2}" y="${h / 2 - thumbH / 2}" width="${thumbW}" height="${thumbH}" preserveAspectRatio="xMidYMid meet"/>
  </g>
</svg>`;
}

export function buildFluxButtonSVG(w, h, dataUrl) {
  return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <g id="normal">
    <image xlink:href="${dataUrl}" x="2" y="2" width="${w - 4}" height="${h - 4}"/>
  </g>
  <g id="pressed" display="none">
    <image xlink:href="${dataUrl}" x="2" y="2" width="${w - 4}" height="${h - 4}" opacity="0.7"/>
  </g>
</svg>`;
}

